#include<bits/stdc++.h>
using namespace std;

long long n, a[1000001], maxa = 0, mina = 10000000000000;

int main() {
	cin >> n;
	for (int i = 0; i < n; i++) scanf("%d", &a[i]);
	for (int i = 0; i < n; i++) {
		maxa = max(a[i], maxa);
		mina = min(a[i], mina);
	}
	for (int i = 0; i < n; i++) {
		printf("%d ", maxa - a[i]);
	}
	printf("\n");
	for (int i = 0; i < n; i++) {
		printf("%d ", a[i] - mina);
	}
	return 0;
}
